<?php $payload=$share['payload'];$isReview=$share['type']==='review';?>
<section class="shared-wrap"><article class="share-card" data-share-card data-share-title="<?=e($isReview?$payload['product_name']:$payload['name'])?>" data-share-rating="<?=e($isReview?(string)$payload['overall_rating']:'')?>"><p class="eyebrow">Ausdrücklich geteilt · SnackQuest</p><?php if($isReview):?><h1><?=e($payload['product_name'])?></h1><p><?=e($payload['brand'])?></p><div class="share-score"><strong><?=e($payload['overall_rating'])?></strong><span>/10</span></div><dl><div><dt>Geschmack</dt><dd><?=e($payload['taste_rating']??'–')?></dd></div><div><dt>Textur</dt><dd><?=e($payload['texture_rating']??'–')?></dd></div><div><dt>Preis-Leistung</dt><dd><?=e($payload['value_rating']??'–')?></dd></div><div><dt>Wieder kaufen</dt><dd><?=e(['yes'=>'Ja','maybe'=>'Vielleicht','no'=>'Nein'][$payload['buy_again']]??'–')?></dd></div></dl><?php if(!empty($payload['tags'])):?><div class="product-flags"><?php foreach($payload['tags'] as $tag):?><span><?=e($tag)?></span><?php endforeach;?></div><?php endif;?><?php else:?><h1><?=e($payload['name'])?></h1><p><?=e($payload['description'])?></p><ol class="shared-list"><?php foreach($payload['items'] as $item):?><li><?=e($item['product_name'])?></li><?php endforeach;?></ol><?php endif;?><p class="fineprint">Momentaufnahme vom <?=e(date('d.m.Y',strtotime((string)$share['created_at'])))?>. Der Eigentümer kann diesen Link jederzeit widerrufen.</p></article><div class="button-row"><button class="button" type="button" data-native-share>Teilen</button><button class="button button-secondary" type="button" data-download-card>Bildkarte laden</button></div></section>
